export function getImageByIndex(chartObj, index, paneid) {
    let imagePallete = chartObj.imagePallete;

    if (!imagePallete) {
        return;
    }

    let hierarchical = chartObj.dataObject.hierarchical;
    if (chartObj.dataObject.categoryHierarchy && hierarchical && hierarchical.pivot && paneid) {
        paneid = paneid || '0_0';
        let gridOptions = hierarchical.gridOptions;
        let renderer = gridOptions[paneid].renderer[index],
            legendIndex = renderer.commonRendererProp().params.legendIndex;

        return imagePallete[legendIndex % imagePallete.length];
    } else {
        return imagePallete[index % imagePallete.length];
    }
}
